public int compareTo(Fraction object) {
    if (object == null) {
        throw new NullPointerException("Cannot compare to null");
    }
    if (denominator == 0 || object.denominator == 0) {
        throw new ArithmeticException("Cannot compare fractions with zero denominator");
    }
    int thisNumerator = numerator * object.denominator;
    int otherNumerator = object.numerator * denominator;
    if (thisNumerator < otherNumerator) {
        return -1;
    } else if (thisNumerator > otherNumerator) {
        return 1;
    } else {
        return 0;
    }
}

public int compareTo(Fraction object) {
    if (object == null) {
        throw new NullPointerException("Object to compare cannot be null");
    }
    long nOd = (long) this.numerator * object.denominator;
    long dOn = (long) this.denominator * object.numerator;
    if (nOd < dOn) {
        return -1;
    } else if (nOd > dOn) {
        return 1;
    } else {
        return 0;
    }
}

public int compareTo(Fraction object) {
    if (object == null) {
        throw new NullPointerException("Cannot compare to null");
    }
    if (denominator == 0 || object.denominator == 0) {
        throw new ArithmeticException("Comparison not possible with zero denominator");
    }
    long nOd = numerator * object.denominator;
    long dOn = denominator * object.numerator;
    return (nOd < dOn) ? -1 : ((nOd > dOn) ? +1 : 0);
}

